namespace sv_ff64043c28764c2cbf6f4fae6506aadf.Services;

/// <summary>
/// Scoped service that holds the currently selected warehouse for a single user circuit.
/// Fires <see cref="OnChanged"/> so any subscribing component can re-render.
/// </summary>
public sealed class WarehouseState
{
    public static readonly (string Id, string Name)[] Warehouses =
    [
        ("WH1", "Warehouse A"),
        ("WH2", "Warehouse B"),
        ("WH3", "Warehouse C"),
    ];

    public string SelectedWarehouseId { get; private set; } = Warehouses[0].Id;

    public event Func<Task>? OnChanged;

    public async Task SetWarehouseAsync(string warehouseId)
    {
        if (SelectedWarehouseId == warehouseId)
            return;

        SelectedWarehouseId = warehouseId;

        if (OnChanged is not null)
            await OnChanged.Invoke();
    }
}

namespace sv_ff64043c28764c2cbf6f4fae6506aadf.Services;

/// <summary>
/// Scoped service that provides low-stock alert counts and notifies all
/// subscribers when the count changes. Because it is scoped, each Blazor
/// Server circuit (user) gets its own instance and independent state.
/// </summary>
public sealed class InventoryAlertService
{
    private readonly Random _random = new();

    public int CurrentLowStockCount { get; private set; }

    /// <summary>
    /// Raised after <see cref="RefreshAsync"/> updates the count.
    /// All components that subscribe to this event will be notified,
    /// regardless of their position in the component tree.
    /// </summary>
    public event Func<Task>? OnAlertCountChanged;

    /// <summary>
    /// Simulates a database query that returns the number of items
    /// below minimum stock levels for the given warehouse.
    /// </summary>
    public Task<int> GetLowStockCountAsync(string warehouseId)
    {
        // Simulate async DB call
        var count = _random.Next(0, 16);
        return Task.FromResult(count);
    }

    /// <summary>
    /// Fetches a new count and broadcasts the change to all subscribers.
    /// </summary>
    public async Task RefreshAsync(string warehouseId)
    {
        CurrentLowStockCount = await GetLowStockCountAsync(warehouseId);

        if (OnAlertCountChanged is not null)
            await OnAlertCountChanged.Invoke();
    }
}

