@* Interactive warehouse selector — rendered as an island inside the static layout. *@
@rendermode InteractiveServer
@inject WarehouseState WarehouseState

<div class="warehouse-selector">
    <label class="form-label text-white small mb-1">Current Warehouse</label>
    <select class="form-select form-select-sm"
            value="@WarehouseState.SelectedWarehouseId"
            @onchange="OnWarehouseChanged">
        @foreach (var (id, name) in Services.WarehouseState.Warehouses)
        {
            <option value="@id">@name</option>
        }
    </select>
</div>

@code {
    private async Task OnWarehouseChanged(ChangeEventArgs e)
