@inject WarehouseState WarehouseState

<PageTitle>Dashboard</PageTitle>

<h1>Warehouse Dashboard</h1>
<p class="text-muted">
    Viewing: <strong>@GetWarehouseName(WarehouseState.SelectedWarehouseId)</strong>
</p>

<div class="row g-4 mt-2">
    <div class="col-md-4">
        <div class="card @(AlertService.CurrentLowStockCount > 0 ? "border-danger" : "border-success")">
            <div class="card-body text-center">
                <h5 class="card-title">Low-Stock Alerts</h5>
                <p class="display-4 @(AlertService.CurrentLowStockCount > 0 ? "text-danger" : "text-success")">
                    @AlertService.CurrentLowStockCount
                </p>
                <p class="text-muted small">
                    Items below minimum level
                </p>
            </div>
        </div>
    </div>

    <div class="col-md-4">
        <div class="card">
            <div class="card-body text-center">
                <h5 class="card-title">Polling Status</h5>
                <p class="mb-1">
                    @if (_isPolling)
                    {
                        <span class="badge bg-success">Active</span>
                    }
                    else
                    {
                        <span class="badge bg-secondary">Stopped</span>
                    }
                </p>
                <p class="text-muted small mb-0">Refreshes every 10 seconds</p>
            </div>
        </div>
    </div>

    <div class="col-md-4">
        <div class="card">
            <div class="card-body text-center">
                <h5 class="card-title">Last Updated</h5>
                <p class="display-6">@(_lastUpdated?.ToString("HH:mm:ss") ?? "—")</p>
            </div>
        </div>
    </div>
</div>

@code {
    private CancellationTokenSource? _cts;
    private bool _isPolling;
    private DateTime? _lastUpdated;

    protected override async Task OnInitializedAsync()
    {
        AlertService.OnAlertCountChanged += OnAlertCountChanged;
        WarehouseState.OnChanged += OnWarehouseChanged;

        // Initial fetch
        await AlertService.RefreshAsync(WarehouseState.SelectedWarehouseId);
        _lastUpdated = DateTime.Now;

        StartPolling();
    }

    private void StartPolling()
    {
        _cts = new CancellationTokenSource();
        _isPolling = true;
        _ = PollLoopAsync(_cts.Token);
    }

    private async Task PollLoopAsync(CancellationToken ct)
    {
        while (!ct.IsCancellationRequested)
        {
            try
            {
                await Task.Delay(TimeSpan.FromSeconds(10), ct);
                await AlertService.RefreshAsync(WarehouseState.SelectedWarehouseId);
                _lastUpdated = DateTime.Now;
                await InvokeAsync(StateHasChanged);
            }
            catch (OperationCanceledException)
            {
                break;
            }
        }
    }

    private async Task OnAlertCountChanged()
    {
        await InvokeAsync(StateHasChanged);
    }

    private async Task OnWarehouseChanged()
    {
        // Restart polling for the new warehouse
        await StopPollingAsync();
        await AlertService.RefreshAsync(WarehouseState.SelectedWarehouseId);
        _lastUpdated = DateTime.Now;
        StartPolling();
        await InvokeAsync(StateHasChanged);
    }

    private async Task StopPollingAsync()
    {
        _isPolling = false;
        if (_cts is not null)
        {
            await _cts.CancelAsync();
            _cts.Dispose();
            _cts = null;
        }
    }

    private static string GetWarehouseName(string id) =>
        Services.WarehouseState.Warehouses
            .FirstOrDefault(w => w.Id == id).Name ?? id;

    public async ValueTask DisposeAsync()
    {
        AlertService.OnAlertCountChanged -= OnAlertCountChanged;
        WarehouseState.OnChanged -= OnWarehouseChanged;
        await StopPollingAsync();
    }
}

